window.CTR_LEGAL_I18N={"privacy":{"en":{"title":"Privacy policy","notice":"Effective 22 July 2026. This policy describes the current free stage of the service.","h_controller":"Who processes data","p_controller":"ChinaTradeResolve is an independent commercial-dispute support project operating from Serbia. Contact: chinatraderesolve.support@gmail.com.","h_data":"Data collected","p_data":"The application collects name, email, country, language, order details and a short dispute description. After selection, up to 5 key files may be requested separately. Payment-card data is not collected.","h_purpose":"How data is used","p_purpose":"Data is used to register and screen applications, communicate with applicants, review cases, protect the service from abuse and meet mandatory legal requirements.","h_ai":"AI processing","p_ai":"With separate voluntary consent, AI may help organise information and prepare drafts. Material conclusions and outgoing documents require human review. The public AI chat is not stored in the case database.","h_share":"Data recipients","p_share":"Access may be provided only to infrastructure, email and configured AI providers as necessary to operate the service. Data is not sold and is not sent to a supplier or marketplace without your decision.","h_store":"Retention and deletion","p_store":"Closed cases are scheduled for anonymisation after 90 days by default. Retention may be extended for an active request, security or a mandatory legal requirement. Provider logs and backups may follow provider retention rules.","h_rights":"Your rights","p_rights":"You may request access, correction or deletion and may withdraw AI consent for future processing. Email the contact address and include your case reference.","h_security":"Security","p_security":"Do not send passwords, seed phrases, private keys, full card numbers or unrelated materials. Internet transmission cannot be guaranteed to be completely secure.","back":"Return to website"},"fr":{"title":"Politique de confidentialité","notice":"En vigueur depuis le 22 juillet 2026. Cette politique décrit la phase gratuite actuelle du service.","h_controller":"Qui traite les données","p_controller":"ChinaTradeResolve est un projet indépendant d’assistance commerciale aux litiges, exploité depuis la Serbie. Contact : chinatraderesolve.support@gmail.com.","h_data":"Données collectées","p_data":"La demande recueille le nom, l’adresse e-mail, le pays, la langue, les informations de commande et une brève description du litige. Après sélection, jusqu’à 5 fichiers essentiels peuvent être demandés séparément. Aucune donnée de carte bancaire n’est collectée.","h_purpose":"Utilisation des données","p_purpose":"Les données servent à enregistrer et examiner les demandes, communiquer avec les demandeurs, analyser les dossiers, protéger le service contre les abus et respecter les obligations légales impératives.","h_ai":"Traitement par l’IA","p_ai":"Avec un consentement volontaire distinct, l’IA peut aider à organiser les informations et préparer des brouillons. Les conclusions importantes et les documents sortants nécessitent une vérification humaine. Le chat public n’est pas enregistré dans la base des dossiers.","h_share":"Destinataires des données","p_share":"L’accès peut être accordé uniquement aux prestataires d’infrastructure, de messagerie et d’IA configurés, dans la mesure nécessaire au fonctionnement. Les données ne sont pas vendues et ne sont pas envoyées au fournisseur ou à la plateforme sans votre décision.","h_store":"Conservation et suppression","p_store":"Les dossiers clôturés sont normalement anonymisés après 90 jours. La conservation peut être prolongée pour une demande active, la sécurité ou une obligation légale. Les journaux techniques et sauvegardes peuvent suivre les règles des prestataires.","h_rights":"Vos droits","p_rights":"Vous pouvez demander l’accès, la rectification ou la suppression de vos données et retirer votre consentement à l’IA pour les traitements futurs. Écrivez à l’adresse de contact avec la référence du dossier.","h_security":"Sécurité","p_security":"N’envoyez pas de mots de passe, phrases de récupération, clés privées, numéros complets de carte ou documents sans rapport. La transmission par Internet ne peut être totalement garantie.","back":"Retour au site"},"de":{"title":"Datenschutzerklärung","notice":"Gültig ab 22. Juli 2026. Diese Erklärung beschreibt die aktuelle kostenlose Phase des Dienstes.","h_controller":"Wer Daten verarbeitet","p_controller":"ChinaTradeResolve ist ein unabhängiges Projekt zur kaufmännischen Unterstützung bei Streitfällen mit Sitz in Serbien. Kontakt: chinatraderesolve.support@gmail.com.","h_data":"Erhobene Daten","p_data":"Bei der Antragstellung werden Name, E-Mail, Land, Sprache, Bestelldaten und eine kurze Streitbeschreibung erhoben. Nach Auswahl können separat bis zu 5 zentrale Dateien angefordert werden. Zahlungskartendaten werden nicht erhoben.","h_purpose":"Verwendung der Daten","p_purpose":"Die Daten dienen der Registrierung und Prüfung von Anträgen, der Kommunikation, der Fallprüfung, dem Schutz vor Missbrauch und der Erfüllung zwingender gesetzlicher Pflichten.","h_ai":"KI-Verarbeitung","p_ai":"Mit gesonderter freiwilliger Einwilligung kann KI Informationen ordnen und Entwürfe vorbereiten. Wesentliche Schlussfolgerungen und ausgehende Dokumente erfordern menschliche Prüfung. Der öffentliche KI-Chat wird nicht in der Falldatenbank gespeichert.","h_share":"Empfänger der Daten","p_share":"Zugriff erhalten nur notwendige Infrastruktur-, E-Mail- und konfigurierte KI-Anbieter. Daten werden nicht verkauft und ohne Ihre Entscheidung nicht an Lieferanten oder Marktplätze gesendet.","h_store":"Speicherung und Löschung","p_store":"Geschlossene Fälle werden standardmäßig nach 90 Tagen anonymisiert. Die Frist kann für laufende Anfragen, Sicherheit oder zwingende rechtliche Pflichten verlängert werden. Technische Protokolle und Sicherungen können den Regeln der Anbieter folgen.","h_rights":"Ihre Rechte","p_rights":"Sie können Auskunft, Berichtigung oder Löschung verlangen und die KI-Einwilligung für zukünftige Verarbeitung widerrufen. Schreiben Sie mit Ihrer Fallreferenz an die Kontaktadresse.","h_security":"Sicherheit","p_security":"Senden Sie keine Passwörter, Seed-Phrasen, privaten Schlüssel, vollständigen Kartennummern oder sachfremde Unterlagen. Eine vollkommen sichere Internetübertragung kann nicht garantiert werden.","back":"Zur Website zurückkehren"},"es":{"title":"Política de privacidad","notice":"Vigente desde el 22 de julio de 2026. Esta política describe la fase gratuita actual del servicio.","h_controller":"Quién trata los datos","p_controller":"ChinaTradeResolve es un proyecto independiente de apoyo comercial en disputas operado desde Serbia. Contacto: chinatraderesolve.support@gmail.com.","h_data":"Datos recopilados","p_data":"La solicitud recoge nombre, correo electrónico, país, idioma, datos del pedido y una breve descripción de la disputa. Tras la selección pueden solicitarse por separado hasta 5 archivos clave. No se recopilan datos de tarjetas de pago.","h_purpose":"Uso de los datos","p_purpose":"Los datos se utilizan para registrar y revisar solicitudes, comunicarse con los solicitantes, analizar casos, proteger el servicio frente a abusos y cumplir obligaciones legales obligatorias.","h_ai":"Tratamiento con IA","p_ai":"Con consentimiento voluntario separado, la IA puede ayudar a organizar información y preparar borradores. Las conclusiones importantes y documentos salientes requieren revisión humana. El chat público no se guarda en la base de casos.","h_share":"Destinatarios de los datos","p_share":"Solo pueden acceder los proveedores necesarios de infraestructura, correo y la IA configurada. Los datos no se venden ni se envían al proveedor o plataforma sin su decisión.","h_store":"Conservación y eliminación","p_store":"Los casos cerrados se programan para anonimización después de 90 días por defecto. El plazo puede ampliarse por una solicitud activa, seguridad u obligación legal. Los registros técnicos y copias pueden seguir las reglas de los proveedores.","h_rights":"Sus derechos","p_rights":"Puede solicitar acceso, corrección o eliminación y retirar el consentimiento de IA para tratamientos futuros. Escriba al contacto e incluya la referencia del caso.","h_security":"Seguridad","p_security":"No envíe contraseñas, frases semilla, claves privadas, números completos de tarjeta ni materiales no relacionados. No puede garantizarse una transmisión por Internet totalmente segura.","back":"Volver al sitio web"},"ru":{"title":"Политика конфиденциальности","notice":"Действует с 22 июля 2026 года. Политика описывает текущий бесплатный этап сервиса.","h_controller":"Кто обрабатывает данные","p_controller":"ChinaTradeResolve — независимый проект коммерческой помощи в спорах, работающий из Сербии. Контакт: chinatraderesolve.support@gmail.com.","h_data":"Какие данные собираются","p_data":"На этапе заявки собираются имя, электронная почта, страна, язык, сведения о заказе и краткое описание спора. После отбора могут быть отдельно запрошены до 5 ключевых файлов. Платёжные данные банковских карт не собираются.","h_purpose":"Зачем используются данные","p_purpose":"Данные используются для регистрации заявки, предварительной классификации, связи с заявителем, рассмотрения дела, защиты сервиса от злоупотреблений и выполнения обязательных требований закона.","h_ai":"Использование ИИ","p_ai":"При отдельном добровольном согласии ИИ может помогать систематизировать сведения и готовить черновики. Важные выводы и исходящие документы требуют человеческой проверки. Публичный ИИ-чат не сохраняется в базе дел.","h_share":"Кому могут передаваться данные","p_share":"Доступ может предоставляться только поставщикам инфраструктуры, электронной почты и настроенного ИИ-сервиса в объёме, необходимом для работы. Данные не продаются и не передаются поставщику или площадке без вашего решения.","h_store":"Хранение и удаление","p_store":"Закрытые дела по умолчанию подлежат обезличиванию через 90 дней. Срок может быть продлён, если это необходимо для незавершённого обращения, безопасности или обязательного требования закона. Технические журналы и резервные копии могут храниться по правилам соответствующих провайдеров.","h_rights":"Ваши права","p_rights":"Вы можете запросить доступ, исправление или удаление своих данных, а также отозвать согласие на ИИ-обработку для будущих действий. Напишите на контактный адрес и укажите номер дела.","h_security":"Безопасность","p_security":"Не отправляйте пароли, seed-фразы, приватные ключи, полные номера банковских карт или материалы, не относящиеся к спору. Интернет-передача данных не может быть абсолютно безопасной.","back":"Вернуться на сайт"},"sr":{"title":"Politika privatnosti","notice":"Važi od 22. jula 2026. Ova politika opisuje trenutnu besplatnu fazu usluge.","h_controller":"Ko obrađuje podatke","p_controller":"ChinaTradeResolve je nezavisan projekat komercijalne podrške u sporovima koji radi iz Srbije. Kontakt: chinatraderesolve.support@gmail.com.","h_data":"Podaci koji se prikupljaju","p_data":"Prijava prikuplja ime, email, zemlju, jezik, podatke o porudžbini i kratak opis spora. Nakon izbora može se posebno zatražiti do 5 ključnih fajlova. Podaci platnih kartica se ne prikupljaju.","h_purpose":"Kako se podaci koriste","p_purpose":"Podaci se koriste za evidentiranje i pregled prijava, komunikaciju, analizu slučaja, zaštitu od zloupotrebe i ispunjavanje obaveznih zakonskih zahteva.","h_ai":"AI obrada","p_ai":"Uz posebno dobrovoljno odobrenje, AI može pomoći u organizaciji informacija i pripremi nacrta. Važne zaključke i izlazne dokumente mora proveriti čovek. Javni AI razgovor se ne čuva u bazi slučajeva.","h_share":"Primaoci podataka","p_share":"Pristup mogu dobiti samo neophodni pružaoci infrastrukture, emaila i podešenog AI servisa. Podaci se ne prodaju i ne šalju dobavljaču ili platformi bez vaše odluke.","h_store":"Čuvanje i brisanje","p_store":"Zatvoreni slučajevi se podrazumevano anonimizuju nakon 90 dana. Rok se može produžiti zbog aktivnog zahteva, bezbednosti ili zakonske obaveze. Tehnički zapisi i rezervne kopije mogu pratiti pravila pružalaca.","h_rights":"Vaša prava","p_rights":"Možete tražiti pristup, ispravku ili brisanje i povući AI saglasnost za buduću obradu. Pišite na kontakt adresu i navedite broj slučaja.","h_security":"Bezbednost","p_security":"Ne šaljite lozinke, seed fraze, privatne ključeve, pune brojeve kartica ili nepovezane materijale. Potpuno bezbedan internet prenos ne može biti garantovan.","back":"Povratak na sajt"}},"terms":{"en":{"title":"Terms of use","notice":"Effective 22 July 2026.","h_scope":"Service scope","p_scope":"ChinaTradeResolve provides independent commercial support by helping organise information, assess evidence and prepare draft claims or messages. Acceptance depends on fit, evidence, complexity and available capacity.","h_limits":"No legal representation","p_limits":"The service is not a law firm, does not represent clients in court or arbitration, issue binding legal opinions, or perform laboratory, certification or technical testing.","h_client":"User responsibilities","p_client":"Users provide accurate information, keep original records, have the right to share materials and independently check deadlines, platform rules and final documents before sending.","h_availability":"Free access","p_availability":"No fee is charged for case analysis at the current stage. Submission does not guarantee acceptance, scope, timing or result. Urgent court and arbitration matters are not accepted.","h_changes":"Changes to the service","p_changes":"Features and terms may change. Paid services will not be enabled without advance terms and separate consent. A case already accepted for free will not become paid without explicit consent.","h_contact":"Contact","p_contact":"Questions about these terms may be sent to chinatraderesolve.support@gmail.com.","back":"Return to website"},"fr":{"title":"Conditions d’utilisation","notice":"En vigueur depuis le 22 juillet 2026.","h_scope":"Étendue du service","p_scope":"ChinaTradeResolve fournit une assistance commerciale indépendante pour organiser les informations, évaluer les preuves et préparer des projets de réclamations ou de messages. L’acceptation dépend de l’adéquation, des preuves, de la complexité et de la capacité disponible.","h_limits":"Aucune représentation juridique","p_limits":"Le service n’est pas un cabinet d’avocats, ne représente pas les clients devant les tribunaux ou en arbitrage, ne rend pas d’avis juridiques contraignants et n’effectue pas d’essais de laboratoire, de certification ou techniques.","h_client":"Responsabilités de l’utilisateur","p_client":"L’utilisateur fournit des informations exactes, conserve les originaux, possède le droit de partager les documents et vérifie lui-même les délais, les règles de la plateforme et les documents définitifs avant envoi.","h_availability":"Accès gratuit","p_availability":"Aucun frais n’est facturé pour l’analyse à ce stade. Une demande ne garantit ni l’acceptation, ni l’étendue, ni le délai, ni le résultat. Les affaires judiciaires ou arbitrales urgentes ne sont pas acceptées.","h_changes":"Modifications du service","p_changes":"Les fonctions et conditions peuvent évoluer. Aucun service payant ne sera activé sans conditions préalables et consentement distinct. Un dossier déjà accepté gratuitement ne deviendra pas payant sans accord explicite.","h_contact":"Contact","p_contact":"Les questions concernant ces conditions peuvent être envoyées à chinatraderesolve.support@gmail.com.","back":"Retour au site"},"de":{"title":"Nutzungsbedingungen","notice":"Gültig ab 22. Juli 2026.","h_scope":"Leistungsumfang","p_scope":"ChinaTradeResolve bietet unabhängige kaufmännische Unterstützung beim Ordnen von Informationen, Bewerten von Nachweisen und Erstellen von Entwürfen für Ansprüche oder Nachrichten. Die Annahme hängt von Eignung, Nachweisen, Komplexität und Kapazität ab.","h_limits":"Keine Rechtsvertretung","p_limits":"Der Dienst ist keine Kanzlei, vertritt nicht vor Gericht oder Schiedsgerichten, erteilt keine bindenden Rechtsgutachten und führt keine Labor-, Zertifizierungs- oder technischen Prüfungen durch.","h_client":"Pflichten der Nutzer","p_client":"Nutzer machen richtige Angaben, bewahren Originale auf, dürfen die Unterlagen teilen und prüfen Fristen, Plattformregeln sowie endgültige Dokumente vor dem Versand selbst.","h_availability":"Kostenloser Zugang","p_availability":"Für die Fallanalyse wird derzeit keine Gebühr erhoben. Eine Anfrage garantiert weder Annahme, Umfang, Dauer noch Ergebnis. Dringende Gerichts- und Schiedsverfahren werden nicht angenommen.","h_changes":"Änderungen des Dienstes","p_changes":"Funktionen und Bedingungen können sich ändern. Bezahlte Dienste werden nur mit vorherigen Bedingungen und gesonderter Zustimmung aktiviert. Ein bereits kostenlos angenommener Fall wird ohne ausdrückliche Zustimmung nicht kostenpflichtig.","h_contact":"Kontakt","p_contact":"Fragen zu diesen Bedingungen können an chinatraderesolve.support@gmail.com gesendet werden.","back":"Zur Website zurückkehren"},"es":{"title":"Condiciones de uso","notice":"Vigentes desde el 22 de julio de 2026.","h_scope":"Alcance del servicio","p_scope":"ChinaTradeResolve presta apoyo comercial independiente para organizar información, evaluar pruebas y preparar borradores de reclamaciones o mensajes. La aceptación depende del encaje, las pruebas, la complejidad y la capacidad disponible.","h_limits":"Sin representación legal","p_limits":"El servicio no es un despacho de abogados, no representa ante tribunales o arbitrajes, no emite opiniones jurídicas vinculantes ni realiza pruebas de laboratorio, certificación o técnicas.","h_client":"Responsabilidades del usuario","p_client":"El usuario aporta información correcta, conserva originales, tiene derecho a compartir los materiales y comprueba por sí mismo los plazos, reglas de plataforma y documentos finales antes de enviarlos.","h_availability":"Acceso gratuito","p_availability":"En la fase actual no se cobra por el análisis. Enviar una solicitud no garantiza aceptación, alcance, plazo ni resultado. No se aceptan asuntos judiciales o arbitrales urgentes.","h_changes":"Cambios del servicio","p_changes":"Las funciones y condiciones pueden cambiar. No se activarán servicios de pago sin condiciones previas y consentimiento separado. Un caso ya aceptado gratis no pasará a ser de pago sin consentimiento explícito.","h_contact":"Contacto","p_contact":"Las preguntas sobre estas condiciones pueden enviarse a chinatraderesolve.support@gmail.com.","back":"Volver al sitio web"},"ru":{"title":"Условия использования","notice":"Действуют с 22 июля 2026 года.","h_scope":"Объём сервиса","p_scope":"ChinaTradeResolve оказывает независимую коммерческую помощь: помогает организовать сведения, оценить доказательства и подготовить черновики претензий или сообщений. Принятие заявки зависит от профиля дела, доказательств, сложности и доступной мощности.","h_limits":"Не юридическое представительство","p_limits":"Сервис не является юридической фирмой, не представляет клиентов в суде или арбитраже, не выдаёт обязательных юридических заключений и не выполняет лабораторные, сертификационные или технические испытания.","h_client":"Обязанности пользователя","p_client":"Пользователь предоставляет точные сведения, хранит оригиналы документов, имеет право передавать материалы и самостоятельно проверяет сроки, правила площадки и окончательные документы до отправки.","h_availability":"Бесплатный доступ","p_availability":"На текущем этапе плата за анализ дела не взимается. Подача заявки не гарантирует принятие, конкретный объём помощи, срок выполнения или результат. Срочные судебные и арбитражные дела не принимаются.","h_changes":"Изменения сервиса","p_changes":"Функции и условия могут изменяться. Платные услуги не будут подключены без предварительной публикации условий и отдельного согласия пользователя. Уже принятое бесплатное дело не станет платным без явного согласия.","h_contact":"Контакт","p_contact":"Вопросы по условиям можно направлять на chinatraderesolve.support@gmail.com.","back":"Вернуться на сайт"},"sr":{"title":"Uslovi korišćenja","notice":"Važe od 22. jula 2026.","h_scope":"Obim usluge","p_scope":"ChinaTradeResolve pruža nezavisnu komercijalnu podršku u organizovanju informacija, proceni dokaza i pripremi nacrta zahteva ili poruka. Prihvatanje zavisi od podobnosti, dokaza, složenosti i kapaciteta.","h_limits":"Nema pravnog zastupanja","p_limits":"Usluga nije advokatska kancelarija, ne zastupa pred sudom ili arbitražom, ne daje obavezujuća pravna mišljenja i ne obavlja laboratorijska, sertifikaciona ili tehnička ispitivanja.","h_client":"Obaveze korisnika","p_client":"Korisnik daje tačne podatke, čuva originale, ima pravo da deli materijale i sam proverava rokove, pravila platforme i konačne dokumente pre slanja.","h_availability":"Besplatan pristup","p_availability":"U trenutnoj fazi analiza se ne naplaćuje. Prijava ne garantuje prihvatanje, obim, rok ili ishod. Hitni sudski i arbitražni predmeti se ne prihvataju.","h_changes":"Izmene usluge","p_changes":"Funkcije i uslovi mogu se menjati. Plaćene usluge neće biti uključene bez prethodnih uslova i posebne saglasnosti. Već besplatno prihvaćen slučaj neće postati plaćen bez izričite saglasnosti.","h_contact":"Kontakt","p_contact":"Pitanja o uslovima mogu se poslati na chinatraderesolve.support@gmail.com.","back":"Povratak na sajt"}},"refund":{"en":{"title":"Payment, cancellation and refund policy","notice":"Effective 22 July 2026. The service is currently free.","h_free":"Free stage","p_free":"ChinaTradeResolve does not currently charge for application review, so refunds of service fees do not apply.","h_support":"Voluntary support","p_support":"Voluntary financial support is not payment for case review, does not create priority and does not guarantee work or an outcome. It is available only after the operator explicitly enables it.","h_errors":"Mistaken transfers","p_errors":"Blockchain transfers are generally irreversible. A mistaken-transfer request may be emailed to the contact address, but a refund is not guaranteed and depends on identification, applicable law and provider or network rules.","h_future":"Future paid services","p_future":"Before any service payment is accepted, separate price, cancellation, timing and refund terms will be published. Payment will not guarantee recovery from a supplier.","back":"Return to website"},"fr":{"title":"Politique de paiement, d’annulation et de remboursement","notice":"En vigueur depuis le 22 juillet 2026. Le service est actuellement gratuit.","h_free":"Phase gratuite","p_free":"ChinaTradeResolve ne facture actuellement pas l’examen des demandes ; aucun remboursement de frais de service ne s’applique donc.","h_support":"Soutien volontaire","p_support":"Le soutien financier volontaire n’est pas le paiement d’une analyse, ne crée aucune priorité et ne garantit ni travail ni résultat. Il n’est disponible qu’après activation explicite par l’opérateur.","h_errors":"Transferts erronés","p_errors":"Les transferts blockchain sont généralement irréversibles. Une demande concernant un transfert erroné peut être envoyée par e-mail, mais aucun remboursement n’est garanti et dépend de l’identification, du droit applicable et des règles du réseau ou du prestataire.","h_future":"Futurs services payants","p_future":"Avant toute facturation, des conditions distinctes sur le prix, l’annulation, les délais et le remboursement seront publiées. Le paiement ne garantira pas un recouvrement auprès du fournisseur.","back":"Retour au site"},"de":{"title":"Zahlungs-, Stornierungs- und Erstattungsrichtlinie","notice":"Gültig ab 22. Juli 2026. Der Dienst ist derzeit kostenlos.","h_free":"Kostenlose Phase","p_free":"ChinaTradeResolve erhebt derzeit keine Gebühr für die Antragsprüfung; eine Erstattung von Servicegebühren findet daher nicht statt.","h_support":"Freiwillige Unterstützung","p_support":"Freiwillige finanzielle Unterstützung ist keine Bezahlung der Fallprüfung, schafft keine Priorität und garantiert weder Leistung noch Ergebnis. Sie ist nur nach ausdrücklicher Aktivierung verfügbar.","h_errors":"Fehlüberweisungen","p_errors":"Blockchain-Überweisungen sind gewöhnlich unumkehrbar. Anfragen zu Fehlüberweisungen können per E-Mail gestellt werden, eine Erstattung ist jedoch nicht garantiert und hängt von Identifizierung, Recht und Netzwerk- oder Anbieterregeln ab.","h_future":"Zukünftige kostenpflichtige Dienste","p_future":"Vor Annahme einer Zahlung werden gesonderte Preis-, Stornierungs-, Zeit- und Erstattungsbedingungen veröffentlicht. Eine Zahlung garantiert keine Rückforderung beim Lieferanten.","back":"Zur Website zurückkehren"},"es":{"title":"Política de pagos, cancelaciones y reembolsos","notice":"Vigente desde el 22 de julio de 2026. El servicio es actualmente gratuito.","h_free":"Fase gratuita","p_free":"ChinaTradeResolve no cobra actualmente por revisar solicitudes, por lo que no se aplica un reembolso de tarifas de servicio.","h_support":"Apoyo voluntario","p_support":"El apoyo financiero voluntario no es pago por revisar un caso, no crea prioridad y no garantiza trabajo ni resultado. Solo está disponible después de su activación explícita.","h_errors":"Transferencias erróneas","p_errors":"Las transferencias blockchain suelen ser irreversibles. Puede enviarse una solicitud por error al correo de contacto, pero el reembolso no está garantizado y depende de la identificación, la ley y las reglas de la red o proveedor.","h_future":"Futuros servicios de pago","p_future":"Antes de aceptar pagos se publicarán condiciones separadas sobre precio, cancelación, plazos y reembolso. El pago no garantizará recuperar dinero del proveedor.","back":"Volver al sitio web"},"ru":{"title":"Политика оплаты, отмены и возврата","notice":"Действует с 22 июля 2026 года. На текущем этапе сервис бесплатный.","h_free":"Бесплатный этап","p_free":"ChinaTradeResolve сейчас не взимает плату за анализ заявок. Поэтому возврат платы за услугу на текущем этапе не применяется.","h_support":"Добровольная поддержка","p_support":"Добровольная финансовая поддержка не является оплатой рассмотрения дела, не создаёт приоритет и не гарантирует работу или результат. Она доступна только после отдельного явного включения оператором.","h_errors":"Ошибочные переводы","p_errors":"Переводы в блокчейне обычно необратимы. Запрос об ошибочном переводе можно направить на контактный адрес, однако возврат не гарантируется и зависит от возможности идентифицировать перевод, применимого закона и правил соответствующей сети или провайдера.","h_future":"Будущие платные услуги","p_future":"До приёма любой оплаты за услуги будет опубликована отдельная информация о цене, отмене, сроках и возврате. Оплата не будет означать гарантию возврата денег от поставщика.","back":"Вернуться на сайт"},"sr":{"title":"Politika plaćanja, otkazivanja i povraćaja","notice":"Važi od 22. jula 2026. Usluga je trenutno besplatna.","h_free":"Besplatna faza","p_free":"ChinaTradeResolve trenutno ne naplaćuje pregled prijava, pa se povraćaj naknade za uslugu ne primenjuje.","h_support":"Dobrovoljna podrška","p_support":"Dobrovoljna finansijska podrška nije plaćanje pregleda slučaja, ne daje prioritet i ne garantuje rad ili ishod. Dostupna je samo nakon izričitog uključivanja.","h_errors":"Pogrešni transferi","p_errors":"Blockchain transferi su uglavnom nepovratni. Zahtev zbog greške može se poslati emailom, ali povraćaj nije garantovan i zavisi od identifikacije, zakona i pravila mreže ili pružaoca.","h_future":"Buduće plaćene usluge","p_future":"Pre prihvatanja bilo koje uplate biće objavljeni posebni uslovi o ceni, otkazivanju, rokovima i povraćaju. Plaćanje neće garantovati povraćaj od dobavljača.","back":"Povratak na sajt"}},"ai-notice":{"en":{"title":"AI use notice","notice":"Effective 22 July 2026.","h_purpose":"Purpose","p_purpose":"AI may help structure information, identify dates and contradictions, compare statements and prepare preliminary drafts.","h_chat":"Public AI assistant","p_chat":"The public assistant answers general questions. The chat is not stored in the case database; a limited recent conversation is sent to the configured AI provider to produce a response. Do not enter confidential details or full documents.","h_case":"Application processing","p_case":"AI analysis of an application is used only with separate voluntary consent. Without consent, built-in rules and, where needed, manual review are used.","h_human":"Human review","p_human":"AI does not make final decisions and does not independently contact suppliers, marketplaces, banks or authorities. Material conclusions require human review.","h_consent":"Consent and withdrawal","p_consent":"Consent may be refused or withdrawn for future processing by emailing the contact address with the case reference. Withdrawal does not undo processing lawfully completed before the request.","h_provider":"Providers and retention","p_provider":"A configured external provider is used for AI functions. Requests use disabled response storage where supported, although technical logs may be processed under the provider’s rules.","back":"Return to website"},"fr":{"title":"Avis sur l’utilisation de l’IA","notice":"En vigueur depuis le 22 juillet 2026.","h_purpose":"Objectif","p_purpose":"L’IA peut aider à structurer les informations, repérer les dates et contradictions, comparer les déclarations et préparer des brouillons préliminaires.","h_chat":"Assistant IA public","p_chat":"L’assistant public répond à des questions générales. Le chat n’est pas enregistré dans la base des dossiers ; une partie limitée de la conversation récente est envoyée au prestataire d’IA configuré pour produire une réponse. N’entrez pas d’informations confidentielles ni de documents complets.","h_case":"Traitement des demandes","p_case":"L’analyse d’une demande par IA n’est utilisée qu’avec un consentement volontaire distinct. Sans consentement, des règles intégrées et, si nécessaire, une vérification manuelle sont utilisées.","h_human":"Vérification humaine","p_human":"L’IA ne prend pas de décision finale et ne contacte pas seule les fournisseurs, plateformes, banques ou autorités. Les conclusions importantes nécessitent une vérification humaine.","h_consent":"Consentement et retrait","p_consent":"Le consentement peut être refusé ou retiré pour les traitements futurs en écrivant à l’adresse de contact avec la référence du dossier. Le retrait n’annule pas les traitements déjà effectués légalement.","h_provider":"Prestataires et conservation","p_provider":"Un prestataire externe configuré est utilisé pour les fonctions d’IA. Le stockage des réponses est désactivé lorsque cela est pris en charge, mais des journaux techniques peuvent être traités selon les règles du prestataire.","back":"Retour au site"},"de":{"title":"Hinweis zur Nutzung von KI","notice":"Gültig ab 22. Juli 2026.","h_purpose":"Zweck","p_purpose":"KI kann Informationen strukturieren, Daten und Widersprüche erkennen, Aussagen vergleichen und vorläufige Entwürfe erstellen.","h_chat":"Öffentlicher KI-Assistent","p_chat":"Der öffentliche Assistent beantwortet allgemeine Fragen. Der Chat wird nicht in der Falldatenbank gespeichert; ein begrenzter Teil der letzten Unterhaltung wird an den konfigurierten KI-Anbieter gesendet. Geben Sie keine vertraulichen Daten oder vollständigen Dokumente ein.","h_case":"Antragsverarbeitung","p_case":"Eine KI-Analyse des Antrags erfolgt nur mit gesonderter freiwilliger Einwilligung. Ohne Einwilligung werden integrierte Regeln und bei Bedarf manuelle Prüfung verwendet.","h_human":"Menschliche Prüfung","p_human":"KI trifft keine endgültigen Entscheidungen und kontaktiert nicht selbstständig Lieferanten, Marktplätze, Banken oder Behörden. Wesentliche Schlussfolgerungen erfordern menschliche Prüfung.","h_consent":"Einwilligung und Widerruf","p_consent":"Die Einwilligung kann verweigert oder für zukünftige Verarbeitung per E-Mail mit Fallreferenz widerrufen werden. Der Widerruf macht rechtmäßig bereits erfolgte Verarbeitung nicht rückgängig.","h_provider":"Anbieter und Speicherung","p_provider":"Für KI-Funktionen wird ein konfigurierter externer Anbieter genutzt. Antwortspeicherung wird soweit unterstützt deaktiviert; technische Protokolle können nach Anbieterregeln verarbeitet werden.","back":"Zur Website zurückkehren"},"es":{"title":"Aviso sobre el uso de IA","notice":"Vigente desde el 22 de julio de 2026.","h_purpose":"Finalidad","p_purpose":"La IA puede ayudar a estructurar información, detectar fechas y contradicciones, comparar declaraciones y preparar borradores preliminares.","h_chat":"Asistente público de IA","p_chat":"El asistente público responde preguntas generales. El chat no se guarda en la base de casos; una parte limitada de la conversación reciente se envía al proveedor de IA configurado. No introduzca datos confidenciales ni documentos completos.","h_case":"Tratamiento de solicitudes","p_case":"El análisis de una solicitud con IA solo se usa con consentimiento voluntario separado. Sin consentimiento se utilizan reglas integradas y, cuando sea necesario, revisión manual.","h_human":"Revisión humana","p_human":"La IA no toma decisiones finales ni contacta por sí sola con proveedores, plataformas, bancos o autoridades. Las conclusiones importantes requieren revisión humana.","h_consent":"Consentimiento y retirada","p_consent":"Puede rechazar o retirar el consentimiento para tratamientos futuros escribiendo al contacto con la referencia del caso. La retirada no revierte el tratamiento realizado legalmente antes de la solicitud.","h_provider":"Proveedores y conservación","p_provider":"Se utiliza un proveedor externo configurado para las funciones de IA. Se desactiva el almacenamiento de respuestas cuando es compatible, aunque pueden tratarse registros técnicos según sus reglas.","back":"Volver al sitio web"},"ru":{"title":"Уведомление об использовании ИИ","notice":"Действует с 22 июля 2026 года.","h_purpose":"Цель","p_purpose":"ИИ может помогать структурировать информацию, находить даты и противоречия, сравнивать утверждения и готовить предварительные черновики.","h_chat":"Публичный ИИ-помощник","p_chat":"Публичный помощник отвечает на общие вопросы. Чат не сохраняется в базе дел; ограниченная недавняя переписка передаётся настроенному ИИ-провайдеру для формирования ответа. Не вводите конфиденциальные сведения или полные документы.","h_case":"Обработка заявки","p_case":"ИИ-анализ конкретной заявки используется только при отдельном добровольном согласии. При отсутствии согласия применяется встроенная проверка по правилам и, при необходимости, ручная проверка.","h_human":"Человеческая проверка","p_human":"ИИ не принимает окончательные решения и самостоятельно не связывается с поставщиками, площадками, банками или государственными органами. Важные выводы проверяются человеком.","h_consent":"Согласие и отзыв","p_consent":"Согласие можно не давать или отозвать для будущих действий, написав на контактный адрес и указав номер дела. Отзыв не отменяет обработку, уже выполненную законно до получения запроса.","h_provider":"Провайдеры и хранение","p_provider":"Для ИИ-функций используется настроенный внешний провайдер. Запросы отправляются с отключённым хранением ответа там, где это поддерживается, однако технические журналы могут обрабатываться по правилам провайдера.","back":"Вернуться на сайт"},"sr":{"title":"Obaveštenje o korišćenju AI","notice":"Važi od 22. jula 2026.","h_purpose":"Svrha","p_purpose":"AI može pomoći u strukturiranju informacija, prepoznavanju datuma i protivrečnosti, poređenju izjava i pripremi početnih nacrta.","h_chat":"Javni AI pomoćnik","p_chat":"Javni pomoćnik odgovara na opšta pitanja. Razgovor se ne čuva u bazi slučajeva; ograničen deo nedavne konverzacije šalje se podešenom AI pružaocu radi odgovora. Ne unosite poverljive podatke ili pune dokumente.","h_case":"Obrada prijave","p_case":"AI analiza prijave koristi se samo uz posebno dobrovoljno odobrenje. Bez saglasnosti koriste se ugrađena pravila i, po potrebi, ručni pregled.","h_human":"Ljudska provera","p_human":"AI ne donosi konačne odluke i ne kontaktira samostalno dobavljače, platforme, banke ili organe. Važne zaključke mora proveriti čovek.","h_consent":"Saglasnost i povlačenje","p_consent":"Saglasnost se može odbiti ili povući za buduću obradu slanjem emaila sa brojem slučaja. Povlačenje ne poništava zakonitu obradu završenu pre zahteva.","h_provider":"Pružaoci i čuvanje","p_provider":"Za AI funkcije koristi se podešen spoljni pružalac. Čuvanje odgovora se isključuje kada je podržano, ali tehnički zapisi mogu biti obrađeni prema njegovim pravilima.","back":"Povratak na sajt"}},"disclaimer":{"en":{"title":"Limitation of liability","notice":"Effective 22 July 2026.","h_scope":"Nature of support","p_scope":"ChinaTradeResolve provides commercial information support, analyses supplied materials and helps prepare documents and messages. It is not legal, financial, banking, tax, customs or technical advice.","h_no_result":"No outcome guarantee","p_no_result":"No refund, settlement, successful claim or other result is guaranteed. Outcomes depend on facts, evidence, contracts, payment methods, platform rules, third-party conduct and applicable law.","h_urgent":"Urgent deadlines","p_urgent":"The service is not intended for expiring court, arbitration, payment or platform deadlines. Users must monitor deadlines and seek qualified help immediately where necessary.","h_user":"User decisions","p_user":"Users make their own decisions, verify facts and approve final documents before sending. Drafts and automated classification may contain errors or require clarification.","h_liability":"Reasonable limits","p_liability":"To the extent permitted by law, the project is not liable for indirect loss, lost profit or actions of suppliers, marketplaces, banks or other third parties. Nothing excludes liability that cannot legally be limited.","back":"Return to website"},"fr":{"title":"Limitation de responsabilité","notice":"En vigueur depuis le 22 juillet 2026.","h_scope":"Nature de l’assistance","p_scope":"ChinaTradeResolve fournit une assistance commerciale informative, analyse les documents fournis et aide à préparer des documents et messages. Il ne s’agit pas d’un conseil juridique, financier, bancaire, fiscal, douanier ou technique.","h_no_result":"Aucune garantie de résultat","p_no_result":"Aucun remboursement, accord, succès d’une réclamation ou autre résultat n’est garanti. Le résultat dépend des faits, preuves, contrats, moyens de paiement, règles de plateforme, comportement des tiers et droit applicable.","h_urgent":"Délais urgents","p_urgent":"Le service n’est pas destiné aux délais judiciaires, arbitraux, de paiement ou de plateforme arrivant à expiration. L’utilisateur doit surveiller lui-même les délais et consulter immédiatement un professionnel qualifié si nécessaire.","h_user":"Décisions de l’utilisateur","p_user":"L’utilisateur prend ses propres décisions, vérifie les faits et approuve les documents définitifs avant envoi. Les brouillons et classifications automatiques peuvent contenir des erreurs ou nécessiter des précisions.","h_liability":"Limites raisonnables","p_liability":"Dans la mesure permise par la loi, le projet n’est pas responsable des pertes indirectes, pertes de bénéfice ou actes des fournisseurs, plateformes, banques ou autres tiers. Rien n’exclut une responsabilité qui ne peut légalement être limitée.","back":"Retour au site"},"de":{"title":"Haftungsbeschränkung","notice":"Gültig ab 22. Juli 2026.","h_scope":"Art der Unterstützung","p_scope":"ChinaTradeResolve bietet kaufmännische Informationsunterstützung, analysiert bereitgestellte Materialien und hilft bei Dokumenten und Nachrichten. Dies ist keine Rechts-, Finanz-, Bank-, Steuer-, Zoll- oder technische Beratung.","h_no_result":"Keine Ergebnisgarantie","p_no_result":"Rückzahlung, Einigung, erfolgreicher Anspruch oder ein anderes Ergebnis werden nicht garantiert. Das Ergebnis hängt von Fakten, Nachweisen, Verträgen, Zahlungswegen, Plattformregeln, Dritten und anwendbarem Recht ab.","h_urgent":"Dringende Fristen","p_urgent":"Der Dienst ist nicht für ablaufende Gerichts-, Schieds-, Zahlungs- oder Plattformfristen vorgesehen. Nutzer müssen Fristen selbst überwachen und nötigenfalls sofort qualifizierte Hilfe suchen.","h_user":"Entscheidungen der Nutzer","p_user":"Nutzer treffen eigene Entscheidungen, prüfen Fakten und genehmigen endgültige Dokumente vor dem Versand. Entwürfe und automatische Einstufungen können Fehler enthalten oder Klärung erfordern.","h_liability":"Angemessene Grenzen","p_liability":"Soweit gesetzlich zulässig, haftet das Projekt nicht für indirekte Schäden, entgangenen Gewinn oder Handlungen von Lieferanten, Plattformen, Banken oder anderen Dritten. Unabdingbare Haftung bleibt unberührt.","back":"Zur Website zurückkehren"},"es":{"title":"Limitación de responsabilidad","notice":"Vigente desde el 22 de julio de 2026.","h_scope":"Naturaleza del apoyo","p_scope":"ChinaTradeResolve ofrece apoyo comercial informativo, analiza materiales aportados y ayuda a preparar documentos y mensajes. No es asesoramiento jurídico, financiero, bancario, fiscal, aduanero ni técnico.","h_no_result":"Sin garantía de resultado","p_no_result":"No se garantiza un reembolso, acuerdo, reclamación exitosa ni otro resultado. Depende de hechos, pruebas, contratos, métodos de pago, reglas de plataforma, conducta de terceros y ley aplicable.","h_urgent":"Plazos urgentes","p_urgent":"El servicio no está destinado a plazos judiciales, arbitrales, de pago o de plataforma próximos a vencer. El usuario debe controlar los plazos y buscar ayuda cualificada de inmediato cuando sea necesario.","h_user":"Decisiones del usuario","p_user":"El usuario toma sus propias decisiones, verifica los hechos y aprueba los documentos finales antes de enviarlos. Los borradores y clasificaciones automáticas pueden contener errores o requerir aclaración.","h_liability":"Límites razonables","p_liability":"En la medida permitida por la ley, el proyecto no responde por pérdidas indirectas, lucro cesante o actos de proveedores, plataformas, bancos u otros terceros. No se excluye la responsabilidad que legalmente no pueda limitarse.","back":"Volver al sitio web"},"ru":{"title":"Ограничение ответственности","notice":"Действует с 22 июля 2026 года.","h_scope":"Характер помощи","p_scope":"ChinaTradeResolve предоставляет коммерческую информационную поддержку, анализирует предоставленные материалы и помогает готовить документы и сообщения. Это не юридическая, финансовая, банковская, налоговая, таможенная или техническая консультация.","h_no_result":"Нет гарантии результата","p_no_result":"Возврат средств, урегулирование, победа в споре или иной конкретный результат не гарантируются. Итог зависит от фактов, доказательств, договора, способа оплаты, правил площадки, поведения сторон и применимого права.","h_urgent":"Срочные сроки","p_urgent":"Сервис не предназначен для дел с истекающими судебными, арбитражными, платёжными или платформенными сроками. Пользователь обязан самостоятельно контролировать сроки и при необходимости немедленно обратиться к квалифицированному специалисту.","h_user":"Решения пользователя","p_user":"Пользователь самостоятельно принимает решения, проверяет факты и утверждает окончательные документы перед отправкой. Черновики и автоматическая классификация могут содержать ошибки или требовать уточнения.","h_liability":"Разумные ограничения","p_liability":"В пределах, разрешённых применимым правом, проект не отвечает за косвенные убытки, упущенную выгоду, действия поставщика, площадки, банка или иных третьих лиц. Эти ограничения не исключают ответственность, которую нельзя ограничить законом.","back":"Вернуться на сайт"},"sr":{"title":"Ograničenje odgovornosti","notice":"Važi od 22. jula 2026.","h_scope":"Priroda podrške","p_scope":"ChinaTradeResolve pruža komercijalnu informativnu podršku, analizira dostavljene materijale i pomaže u pripremi dokumenata i poruka. To nije pravni, finansijski, bankarski, poreski, carinski ili tehnički savet.","h_no_result":"Nema garancije ishoda","p_no_result":"Povraćaj, nagodba, uspešan zahtev ili drugi ishod nisu garantovani. Ishod zavisi od činjenica, dokaza, ugovora, načina plaćanja, pravila platforme, trećih lica i primenjivog prava.","h_urgent":"Hitni rokovi","p_urgent":"Usluga nije namenjena rokovima suda, arbitraže, plaćanja ili platforme koji uskoro ističu. Korisnik mora sam pratiti rokove i odmah potražiti kvalifikovanu pomoć kada je potrebno.","h_user":"Odluke korisnika","p_user":"Korisnik sam donosi odluke, proverava činjenice i odobrava konačne dokumente pre slanja. Nacrti i automatska klasifikacija mogu sadržati greške ili zahtevati pojašnjenje.","h_liability":"Razumna ograničenja","p_liability":"U meri dozvoljenoj zakonom, projekat ne odgovara za posrednu štetu, izgubljenu dobit ili postupke dobavljača, platformi, banaka ili drugih trećih lica. Ne isključuje se odgovornost koja se zakonom ne može ograničiti.","back":"Povratak na sajt"}},"sample":{"en":{"tag":"Anonymised example","title":"Sample ChinaTradeResolve case assessment","notice":"This is a fictional example of the output format. It is not legal advice and does not describe a real client.","h_summary":"1. Case summary","problem_label":"Issue:","problem":"The material and contents of the goods differ from the written order.","outcome_label":"Desired outcome:","outcome":"Partial refund or replacement.","status_label":"Current status:","status":"A marketplace dispute is already open.","h_assessment":"2. Preliminary assessment","assessment":"The available documents may support a credible specification-mismatch claim. The allegation of incorrect material appears stronger than a subjective quality complaint. If the supplier disputes the composition, an independent technical review may be required.","h_timeline":"3. Key facts and timeline","li1":"The order description specifies a particular material and contents.","li2":"The supplier later described the material differently.","li3":"Photographs may show that agreed components are missing.","h_matrix":"4. Evidence matrix","th_claim":"Claim","th_materials":"Supporting materials","th_supplier":"Supplier position","th_risk":"Risk","r1c1":"Wrong material","r1c2":"Order, supplier messages, product photographs","r1c3":"The description was general","r1c4":"Without technical testing, the terminology may be disputed","r2c1":"Missing component","r2c2":"Invoice, packing list, photographs","r2c3":"No clear response","r2c4":"It must be shown that the component was part of the final specification","h_strategy":"5. Recommended strategy","s1":"Start with the written order specification.","s2":"Separate measurable mismatches from subjective complaints.","s3":"Request a separate written response to each point.","s4":"Consider an independent review of disputed technical facts.","flow":"Facts → Evidence → Risks → Strategy → Actions","back":"Return to website"},"ru":{"tag":"Обезличенный пример","title":"Пример оценки дела ChinaTradeResolve","notice":"Это вымышленный пример формата результата. Он не является юридической консультацией и не описывает реального клиента.","h_summary":"1. Краткое описание дела","problem_label":"Проблема:","problem":"Материал и комплектация товара отличаются от письменного заказа.","outcome_label":"Желаемый результат:","outcome":"Частичный возврат средств или замена.","status_label":"Текущий статус:","status":"Спор на маркетплейсе уже открыт.","h_assessment":"2. Предварительная оценка","assessment":"Имеющиеся документы могут подтверждать обоснованную претензию по несоответствию спецификации. Утверждение о неверном материале выглядит сильнее субъективной жалобы на качество. Если поставщик оспаривает состав товара, может потребоваться независимая техническая проверка.","h_timeline":"3. Основные факты и хронология","li1":"В описании заказа указан конкретный материал и комплектация.","li2":"Позднее поставщик описал материал иначе.","li3":"На фотографиях могут отсутствовать согласованные компоненты.","h_matrix":"4. Матрица доказательств","th_claim":"Утверждение","th_materials":"Подтверждающие материалы","th_supplier":"Позиция поставщика","th_risk":"Риск","r1c1":"Неверный материал","r1c2":"Заказ, сообщения поставщика, фотографии товара","r1c3":"Описание было общим","r1c4":"Без технической проверки терминология может быть спорной","r2c1":"Недостающий компонент","r2c2":"Инвойс, упаковочный лист, фотографии","r2c3":"Чёткий ответ отсутствует","r2c4":"Нужно доказать, что компонент входил в окончательную спецификацию","h_strategy":"5. Рекомендуемая стратегия","s1":"Начать с письменной спецификации заказа.","s2":"Отделить измеримые несоответствия от субъективных жалоб.","s3":"Запросить отдельный письменный ответ на каждый пункт.","s4":"Рассмотреть независимую проверку спорных технических фактов.","flow":"Факты → Доказательства → Риски → Стратегия → Действия","back":"Вернуться на сайт"},"fr":{"tag":"Exemple anonymisé","title":"Exemple d’évaluation de dossier ChinaTradeResolve","notice":"Il s’agit d’un exemple fictif du format de résultat. Ce document n’est pas un conseil juridique et ne décrit aucun client réel.","h_summary":"1. Résumé du dossier","problem_label":"Problème :","problem":"Le matériau et le contenu des marchandises diffèrent de la commande écrite.","outcome_label":"Résultat souhaité :","outcome":"Remboursement partiel ou remplacement.","status_label":"Statut actuel :","status":"Un litige est déjà ouvert sur la plateforme.","h_assessment":"2. Évaluation préliminaire","assessment":"Les documents disponibles peuvent soutenir une réclamation crédible pour non-conformité aux spécifications. L’allégation relative au mauvais matériau paraît plus solide qu’une plainte subjective sur la qualité. Si le fournisseur conteste la composition, une vérification technique indépendante peut être nécessaire.","h_timeline":"3. Faits essentiels et chronologie","li1":"La description de la commande précise un matériau et un contenu particuliers.","li2":"Le fournisseur a ensuite décrit le matériau différemment.","li3":"Les photographies peuvent montrer l’absence de composants convenus.","h_matrix":"4. Matrice des preuves","th_claim":"Allégation","th_materials":"Éléments justificatifs","th_supplier":"Position du fournisseur","th_risk":"Risque","r1c1":"Mauvais matériau","r1c2":"Commande, messages du fournisseur, photographies du produit","r1c3":"La description était générale","r1c4":"Sans essai technique, la terminologie peut être contestée","r2c1":"Composant manquant","r2c2":"Facture, liste de colisage, photographies","r2c3":"Aucune réponse claire","r2c4":"Il faut démontrer que le composant faisait partie de la spécification finale","h_strategy":"5. Stratégie recommandée","s1":"Commencer par la spécification écrite de la commande.","s2":"Séparer les non-conformités mesurables des plaintes subjectives.","s3":"Demander une réponse écrite distincte pour chaque point.","s4":"Envisager une vérification indépendante des faits techniques contestés.","flow":"Faits → Preuves → Risques → Stratégie → Actions","back":"Retour au site"},"de":{"tag":"Anonymisiertes Beispiel","title":"Beispiel einer ChinaTradeResolve-Fallbewertung","notice":"Dies ist ein fiktives Beispiel für das Ausgabeformat. Es ist keine Rechtsberatung und beschreibt keinen realen Kunden.","h_summary":"1. Fallzusammenfassung","problem_label":"Problem:","problem":"Material und Lieferumfang der Ware weichen von der schriftlichen Bestellung ab.","outcome_label":"Gewünschtes Ergebnis:","outcome":"Teilweise Erstattung oder Ersatz.","status_label":"Aktueller Status:","status":"Auf dem Marktplatz ist bereits ein Streitfall eröffnet.","h_assessment":"2. Vorläufige Bewertung","assessment":"Die vorhandenen Dokumente könnten eine glaubwürdige Forderung wegen Abweichung von der Spezifikation stützen. Die Behauptung eines falschen Materials wirkt stärker als eine subjektive Qualitätsbeschwerde. Bestreitet der Lieferant die Zusammensetzung, kann eine unabhängige technische Prüfung erforderlich sein.","h_timeline":"3. Zentrale Fakten und Zeitablauf","li1":"Die Bestellbeschreibung nennt ein bestimmtes Material und einen bestimmten Lieferumfang.","li2":"Später beschrieb der Lieferant das Material anders.","li3":"Fotos könnten zeigen, dass vereinbarte Komponenten fehlen.","h_matrix":"4. Beweismatrix","th_claim":"Behauptung","th_materials":"Belegende Unterlagen","th_supplier":"Position des Lieferanten","th_risk":"Risiko","r1c1":"Falsches Material","r1c2":"Bestellung, Lieferantennachrichten, Produktfotos","r1c3":"Die Beschreibung war allgemein","r1c4":"Ohne technische Prüfung können die Begriffe strittig sein","r2c1":"Fehlende Komponente","r2c2":"Rechnung, Packliste, Fotos","r2c3":"Keine klare Antwort","r2c4":"Es muss nachgewiesen werden, dass die Komponente Teil der endgültigen Spezifikation war","h_strategy":"5. Empfohlene Strategie","s1":"Mit der schriftlichen Bestellspezifikation beginnen.","s2":"Messbare Abweichungen von subjektiven Beschwerden trennen.","s3":"Zu jedem Punkt eine gesonderte schriftliche Antwort anfordern.","s4":"Eine unabhängige Prüfung strittiger technischer Fakten erwägen.","flow":"Fakten → Nachweise → Risiken → Strategie → Maßnahmen","back":"Zur Website zurückkehren"},"es":{"tag":"Ejemplo anonimizado","title":"Ejemplo de evaluación de un caso de ChinaTradeResolve","notice":"Este es un ejemplo ficticio del formato del resultado. No es asesoramiento jurídico ni describe a un cliente real.","h_summary":"1. Resumen del caso","problem_label":"Problema:","problem":"El material y el contenido de la mercancía difieren del pedido escrito.","outcome_label":"Resultado deseado:","outcome":"Reembolso parcial o sustitución.","status_label":"Estado actual:","status":"Ya hay una disputa abierta en la plataforma.","h_assessment":"2. Evaluación preliminar","assessment":"Los documentos disponibles pueden respaldar una reclamación creíble por incumplimiento de la especificación. La alegación de material incorrecto parece más sólida que una queja subjetiva sobre la calidad. Si el proveedor discute la composición, puede ser necesaria una revisión técnica independiente.","h_timeline":"3. Hechos principales y cronología","li1":"La descripción del pedido especifica un material y un contenido concretos.","li2":"Posteriormente, el proveedor describió el material de otra manera.","li3":"Las fotografías pueden mostrar que faltan componentes acordados.","h_matrix":"4. Matriz de pruebas","th_claim":"Alegación","th_materials":"Materiales de apoyo","th_supplier":"Posición del proveedor","th_risk":"Riesgo","r1c1":"Material incorrecto","r1c2":"Pedido, mensajes del proveedor y fotografías del producto","r1c3":"La descripción era general","r1c4":"Sin una prueba técnica, la terminología puede ser discutida","r2c1":"Componente faltante","r2c2":"Factura, lista de embalaje y fotografías","r2c3":"No hay una respuesta clara","r2c4":"Debe demostrarse que el componente formaba parte de la especificación final","h_strategy":"5. Estrategia recomendada","s1":"Empezar por la especificación escrita del pedido.","s2":"Separar los incumplimientos medibles de las quejas subjetivas.","s3":"Solicitar una respuesta escrita separada para cada punto.","s4":"Considerar una revisión independiente de los hechos técnicos discutidos.","flow":"Hechos → Pruebas → Riesgos → Estrategia → Acciones","back":"Volver al sitio web"},"sr":{"tag":"Anonimizovan primer","title":"Primer procene slučaja ChinaTradeResolve","notice":"Ovo je izmišljeni primer formata rezultata. Nije pravni savet i ne opisuje stvarnog klijenta.","h_summary":"1. Sažetak slučaja","problem_label":"Problem:","problem":"Materijal i sadržaj robe razlikuju se od pisane porudžbine.","outcome_label":"Željeni ishod:","outcome":"Delimičan povraćaj ili zamena.","status_label":"Trenutni status:","status":"Spor na platformi je već otvoren.","h_assessment":"2. Preliminarna procena","assessment":"Dostupna dokumenta mogu podržati verodostojan zahtev zbog neslaganja sa specifikacijom. Tvrdnja o pogrešnom materijalu deluje jače od subjektivne žalbe na kvalitet. Ako dobavljač osporava sastav, može biti potrebna nezavisna tehnička provera.","h_timeline":"3. Ključne činjenice i hronologija","li1":"Opis porudžbine navodi određeni materijal i sadržaj.","li2":"Dobavljač je kasnije drugačije opisao materijal.","li3":"Fotografije mogu pokazati da dogovorene komponente nedostaju.","h_matrix":"4. Matrica dokaza","th_claim":"Tvrdnja","th_materials":"Dokazi","th_supplier":"Stav dobavljača","th_risk":"Rizik","r1c1":"Pogrešan materijal","r1c2":"Porudžbina, poruke dobavljača, fotografije proizvoda","r1c3":"Opis je bio opšti","r1c4":"Bez tehničkog ispitivanja terminologija može biti sporna","r2c1":"Nedostajuća komponenta","r2c2":"Faktura, lista pakovanja, fotografije","r2c3":"Nema jasnog odgovora","r2c4":"Mora se dokazati da je komponenta bila deo konačne specifikacije","h_strategy":"5. Preporučena strategija","s1":"Početi od pisane specifikacije porudžbine.","s2":"Odvojiti merljiva odstupanja od subjektivnih žalbi.","s3":"Zatražiti poseban pisani odgovor na svaku tačku.","s4":"Razmotriti nezavisnu proveru spornih tehničkih činjenica.","flow":"Činjenice → Dokazi → Rizici → Strategija → Aktivnosti","back":"Povratak na sajt"}}};
window.CTR_BOOT_LEGAL=function(pageId){
 const supported=['en','fr','de','es','ru','sr'];
 const all=window.CTR_LEGAL_I18N[pageId]||{};
 const select=document.getElementById('lang');
 function normalize(v){const c=String(v||'').toLowerCase().split('-')[0];return supported.includes(c)?c:'en'}
 function setLang(v){const l=normalize(v),copy=all[l]||all.en||{};document.documentElement.lang=l;if(select)select.value=l;document.querySelectorAll('[data-k]').forEach(el=>{const value=copy[el.dataset.k];if(value!==undefined)el.textContent=value});document.title=copy.title||'ChinaTradeResolve';const back=document.querySelector('[data-back]');if(back)back.href='/?lang='+l;try{localStorage.setItem('ctr_lang_v20',l)}catch(e){}}
 if(select)select.onchange=e=>setLang(e.target.value);
 const query=new URLSearchParams(window.location.search).get('lang');
 let saved='';try{saved=localStorage.getItem('ctr_lang_v20')||localStorage.getItem('ctr_lang_v17')||''}catch(e){};setLang(query||saved||navigator.language||'en');
};
